@app.route('/login')
def login():
    # This `redirect_uri` comes from the client (e.g., a specific tenant's frontend).
    # It tells *our app* where to redirect the user *after* our app successfully processes the OAuth flow.
    requested_post_auth_redirect_uri = request.args.get('redirect_uri')

    if not requested_post_auth_redirect_uri:
        return jsonify({'error': 'Missing "redirect_uri" query parameter.'}), 400

    # Validate the client-provided post-authentication redirect URI against our configured domain.
    configured_domain = app.config['REDIRECT_URI_DOMAIN']
    if configured_domain not in requested_post_auth_redirect_uri:
        app.logger.warning(
            f"Redirect URI validation failed. Provided: '{requested_post_auth_redirect_uri}', "
            f"Required domain substring: '{configured_domain}'"
        )
        return jsonify({
            'error': f'Invalid redirect_uri. It must contain the configured domain: "{configured_domain}".',
            'provided_uri': requested_post_auth_redirect_uri
        }), 403 # Forbidden: Security policy violation

    # Store the validated URI in the session. We'll retrieve this after the OAuth provider
    # redirects back to our /oauth/callback endpoint.
    session['post_auth_redirect_uri'] = requested_post_auth_redirect_uri

    # Initiate the OAuth authorization flow.
    # The `redirect_uri` argument here is the URL of *this application's* callback endpoint.
    # This is the URI that your OAuth provider must be configured to redirect to.
    # `_external=True` ensures that a full, absolute URL is generated for the OAuth provider.
    return oauth.myoauthprovider.authorize_redirect(url_for('callback', _external=True))

@app.route('/oauth/callback')
def callback():
    try:
        # Authlib handles the OAuth 2.0 code exchange for an access token.
        # It automatically uses the current request context to determine the redirect_uri
        # that was sent in the initial authorization request.
        token = oauth.myoauthprovider.authorize_access_token()
    except Exception as e:
        app.logger.error(f"OAuth callback error during token exchange: {e}")
        # Clear any pending redirect URI to prevent unintended redirects on error or retry
        session.pop('post_auth_redirect_uri', None) 
        return jsonify({'error': f'Failed to retrieve access token: {e}'}), 500

    # Store the obtained token in the user's session.
    # In a production application, you would typically persist this token (and refresh token)
    # in a database associated with the user, securely.
    session['user_token'] = token

    # Retrieve the original post-authentication redirect URI from the session.
    # This is where the user's browser will be sent next.
    post_auth_redirect_uri = session.pop('post_auth_redirect_uri', None)

    if post_auth_redirect_uri:
        # Redirect the user to their intended destination within the validated domain.
        return redirect(post_auth_redirect_uri)
    else:
        # Fallback if the post_auth_redirect_uri was lost or not set (e.g., direct access to callback).
        app.logger.warning("Post-authentication redirect URI not found in session after successful login.")
        return jsonify({'message': 'Login successful, but no specific post-auth redirect URI found.'})

@app.route('/profile')
def profile():
    token = session.get('user_token')
    if not token:
        # If no token in session, user is not logged in. Redirect to home.
        return redirect(url_for('index'))

    # In a real application, you would use the access_token to make authenticated
    # API calls to a resource server (e.g., your own backend or the OAuth provider's user info endpoint)
    # to fetch user-specific data.
    
    # For this example, we'll just display some token details.
    user_info = {
        'message': 'Welcome to your profile!',
        'access_token': token.get('access_token', '[hidden]'), # Mask sensitive parts if displaying
        'expires_in': token.get('expires_in', 'N/A'),
        'token_type': token.get('token_type', 'N/A'),
        # You might have 'id_token' or other claims here if using OpenID Connect
        'scope': token.get('scope', app.config['OAUTH_SCOPE']),
        'raw_token_data': token # For debugging, typically not exposed directly
    }
    return jsonify(user_info)

